{
  "name": "gqa_paged_decode_h32_kv8_d128_ps1",
  "description": "Batched Grouped Query Attention decode with a paged KV cache. Captured from Llama-3.1-8B.",
  "axes": {
    "batch_size": {
      "type": "var",
      "description": "Total number of query tokens."
    },
